    32→/// Experience tracker interface for managing unit experience
    33→pub trait ExperienceTracker: Send + Sync {
    34→    /// Check if this object can be trained (gain experience)
    35→    fn is_trainable(&self) -> bool;
    36→    
    37→    /// Check if this object can gain enough experience for the specified levels
    38→    fn can_gain_exp_for_level(&self, levels: i32) -> bool;
    39→    
    40→    /// Grant experience levels to this object
    41→    /// 
    42→    /// # Arguments
    43→    /// * `levels` - Number of levels to gain
    44→    /// * `show_effect` - Whether to show visual effects
    45→    fn gain_exp_for_level(&mut self, levels: i32, show_effect: bool) -> Result<(), String>;
    46→}
