    48→/// Mock experience tracker for testing
    49→pub struct MockExperienceTracker {
    50→    pub current_level: VeterancyLevel,
    51→    pub max_level: VeterancyLevel,
    52→    pub is_trainable: bool,
    53→}
    54→
    55→impl MockExperienceTracker {
    56→    pub fn new(current_level: VeterancyLevel, max_level: VeterancyLevel) -> Self {
    57→        Self {
    58→            current_level,
    59→            max_level,
    60→            is_trainable: true,
    61→        }
    62→    }
    63→}
    64→
    65→impl ExperienceTracker for MockExperienceTracker {
    66→    fn is_trainable(&self) -> bool {
    67→        self.is_trainable
    68→    }
    69→    
    70→    fn can_gain_exp_for_level(&self, levels: i32) -> bool {
    71→        if levels <= 0 {
    72→            return false;
    73→        }
    74→        
    75→        let new_level = self.current_level.saturating_add(levels as VeterancyLevel);
    76→        new_level <= self.max_level
    77→    }
    78→    
    79→    fn gain_exp_for_level(&mut self, levels: i32, show_effect: bool) -> Result<(), String> {
    80→        if !self.can_gain_exp_for_level(levels) {
    81→            return Err("Cannot gain experience for the specified levels".to_string());
    82→        }
    83→        
    84→        self.current_level = self.current_level.saturating_add(levels as VeterancyLevel);
    85→        
    86→        if show_effect {
    87→            println!("Unit gained {} experience levels (now level {})", levels, self.current_level);
    88→        }
    89→        
    90→        Ok(())
    91→    }
    92→}
