   328→/// Veterancy Crate Collide Module
   329→/// 
   330→/// This module implements a crate that grants veterancy experience to units.
   331→/// It can affect a single unit or all units within a specified range.
   332→pub struct VeterancyCrateCollide {
   333→    base: BaseCrateCollide,
   334→    module_data: VeterancyCrateCollideModuleData,
   335→    owner_object_id: ObjectID,
   336→    version: u32,
   337→}
   338→
   339→impl VeterancyCrateCollide {
   340→    /// Create a new VeterancyCrateCollide instance
   341→    /// 
   342→    /// # Arguments
   343→    /// * `object_id` - The ID of the object this module belongs to
   344→    /// * `module_data` - Configuration data for the veterancy crate collision behavior
   345→    pub fn new(object_id: ObjectID, module_data: VeterancyCrateCollideModuleData) -> Self {
   346→        Self {
   347→            base: BaseCrateCollide::new(object_id, module_data.base.clone()),
   348→            module_data,
   349→            owner_object_id: object_id,
   350→            version: 1,
   351→        }
   352→    }
   353→
   354→    /// Get the veterancy crate collision module data
   355→    pub fn get_veterancy_crate_collide_module_data(&self) -> &VeterancyCrateCollideModuleData {
   356→        &self.module_data
   357→    }
   358→
   359→    /// Get the number of levels this crate will grant
   360→    pub fn get_levels_to_gain(&self, owner_veterancy: VeterancyLevel) -> i32 {
   361→        if !self.module_data.adds_owner_veterancy {
   362→            return 1;
   363→        }
   364→        
   365→        // This requires that "regular" is 0, veteran is 1, etc.
   366→        owner_veterancy as i32
   367→    }
   368→
   369→    /// Get the current version of this module for serialization
   370→    pub fn get_version(&self) -> u32 {
   371→        self.version
   372→    }
   373→
   374→    /// Serialize this module's state
   375→    pub fn serialize<T: super::shroud_crate_collide::Serialize>(&self, xfer: &mut T) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
   376→        xfer.write_version(self.version)
   377→            .map_err(|e| Box::new(std::io::Error::new(std::io::ErrorKind::Other, InvalidObject(format!("Serialization failed: {}", e.to_string()))).map_err(|e| Box::new(e) as Box<dyn std::error::Error + Send + Sync>)?;
   378→        
   379→        Ok(())
   380→    }
   381→
   382→    /// Deserialize this module's state
   383→    pub fn deserialize<T: super::shroud_crate_collide::Deserialize>(&mut self, xfer: &mut T) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
   384→        let version = xfer.read_version()
   385→            .map_err(|e| Box::new(std::io::Error::new(std::io::ErrorKind::Other, InvalidObject(format!("Deserialization failed: {}", e.to_string()))).map_err(|e| Box::new(e) as Box<dyn std::error::Error + Send + Sync>)?;
   386→        
   387→        if version != self.version {
   388→            return Err(Box::new(std::io::Error::new(std::io::ErrorKind::Other, InvalidObject(
   389→                format!("Version mismatch: expected {}, got {}", self.version, version)
   390→            ));
   391→        }
   392→        
   393→        Ok(())
   394→    }
   395→
   396→    /// Compute CRC for this module's state
   397→    pub fn compute_crc(&self) -> u32 {
   398→        let mut crc = 0u32;
   399→        crc ^= self.version;
   400→        crc ^= self.module_data.range_of_effect;
   401→        if self.module_data.adds_owner_veterancy { crc ^= 1; }
   402→        if self.module_data.is_pilot { crc ^= 2; }
   403→        crc
   404→    }
   405→
   406→    /// Load post-processing after deserialization
   407→    pub fn load_post_process(&mut self) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
   408→        Ok(())
   409→    }
   410→}
