   412→impl CollideModule for VeterancyCrateCollide {
   413→    fn on_collide(&mut self, other: Option<&dyn GameObject>, loc: &Coord3D, normal: &Coord3D) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
   414→        if let Some(other_obj) = other {
   415→            if self.is_valid_to_execute(other_obj) {
   416→                // Execute the veterancy crate behavior
   417→                let success = self.execute_crate_behavior_internal(other_obj)?;
   418→                if !success {
   419→                    return Err(Box::new(std::io::Error::new(std::io::ErrorKind::Other, InvalidObject("Failed to execute veterancy crate behavior".to_string()));
   420→                }
   421→            }
   422→        }
   423→        
   424→        // Call base implementation for common collision handling
   425→        self.base.on_collide(other, loc, normal)
   426→    }
   427→
   428→    fn would_like_to_collide_with(&self, other: &dyn GameObject) -> bool {
   429→        self.is_valid_to_execute(other)
