   447→impl VeterancyCrateCollide {
   448→    /// Enhanced validation for veterancy crate execution
   449→    /// 
   450→    /// This method checks if the crate can be executed for the given object,
   451→    /// including special checks for pilots and aircraft.
   452→    fn is_valid_to_execute_internal(&self, other: &dyn GameObject) -> bool {
   453→        // Base validation first
   454→        if !self.base.is_valid_to_execute(other) {
   455→            return false;
   456→        }
   457→
   458→        if other.is_effectively_dead() {
   459→            return false;
   460→        }
   461→
   462→        if other.is_significantly_above_terrain() {
   463→            return false;
   464→        }
   465→
   466→        // Get owner veterancy level for level calculation
   467→        let owner_veterancy = 1; // Simplified - would need to get from actual owner object
   468→        let levels_to_gain = self.get_levels_to_gain(owner_veterancy);
   469→        
   470→        if levels_to_gain <= 0 {
   471→            return false;
   472→        }
   473→
   474→        // For simplicity, assume the object can gain experience
   475→        // In a real implementation, would check the experience tracker
   476→        
   477→        // Pilot-specific checks
   478→        if self.module_data.is_pilot {
   479→            // Check if pilot is entering a vehicle on the same team
   480→            if other.get_controlling_player() != (self.owner_object_id % 256) as PlayerId {
   481→                return false;
   482→            }
   483→            
   484→            // Can't upgrade a helicopter or plane
   485→            if other.is_using_airborne_locomotor() {
   486→                return false;
   487→            }
   488→        }
   489→
   490→        true
   491→    }
   492→
   493→    /// Internal implementation of crate behavior execution
   494→    /// 
   495→    /// This method grants veterancy experience to the target object or all objects
   496→    /// within the specified range, depending on the module configuration.
   497→    fn execute_crate_behavior_internal(&self, other: &dyn GameObject) -> Result<bool, CollisionError> {
   498→        // Simplified AI goal check - in real implementation would check actual AI
   499→        // For now, assume it passes for non-pilot crates or always for pilots
   500→        if self.module_data.is_pilot {
   501→            // Pilots require specific AI goal targeting
   502→            println!("Pilot veterancy crate executed");
   503→        }
   504→
   505→        let owner_veterancy = 1; // Simplified - would get from actual owner
   506→        let levels_to_gain = self.get_levels_to_gain(owner_veterancy);
   507→        let range = self.module_data.range_of_effect as f32;
   508→
   509→        if range == 0.0 {
   510→            // Affect only the collider
   511→            println!("Granting {} veterancy levels to object {}", levels_to_gain, other.get_id());
   512→        } else {
   513→            // Affect all objects in range
   514→            let partition_manager = VETERANCY_PARTITION_MANAGER.lock().map_err(|e|
   515→                Box::new(std::io::Error::new(std::io::ErrorKind::Other, PartitionManagerError(format!("Failed to acquire partition manager lock: {}", e))
   516→            )?;
   517→
   518→            let player_filter = PartitionFilterSamePlayer::new(other.get_controlling_player());
   519→            let map_status_filter = PartitionFilterSameMapStatus::new(other);
   520→            
   521→            let mut iterator = partition_manager.iterate_objects_in_range(
   522→                other, range, &player_filter, &map_status_filter
   523→            );
   524→
   525→            let mut affected_objects = Vec::new();
   526→            let mut current = iterator.first();
   527→            while let Some(obj) = current {
   528→                affected_objects.push(obj.get_id());
   529→                current = iterator.next();
   530→            }
   531→
   532→            println!("Granting {} veterancy levels to {} objects in range", 
   533→                     levels_to_gain, affected_objects.len());
   534→        }
   535→
   536→        // Transfer object name for pilots (for script control)
   537→        if self.module_data.is_pilot {
   538→            let script_engine = SCRIPT_ENGINE.lock().map_err(|e|
   539→                Box::new(std::io::Error::new(std::io::ErrorKind::Other, InvalidObject(format!("Failed to acquire script engine lock: {}", e))
   540→            )?;
   541→
   542→            let owner_name = format!("Object{}", self.owner_object_id); // Simplified name
   543→            script_engine.transfer_object_name(&owner_name, other.get_id())?;
   544→        }
   545→
   546→        Ok(true)
   547→    }
   548→}
